INSERT INTO `blog_posts` VALUES (1,'Cách chọn tour trong nước phù hợp ngân sách','Kinh nghiệm','https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=1100&q=80','WebDuLich Team','2026-05-02','Chuẩn bị ngân sách, thời gian và phong cách du lịch trước khi chọn tour giúp chuyến đi nhẹ nhàng hơn.','Khi chọn tour trong nước, bạn nên so sánh lịch trình, điểm tham quan chính, phương tiện, khách sạn, bữa ăn, chính sách trẻ em và ngày khởi hành.'),(2,'Gợi ý lịch trình Đà Nẵng - Hội An 3 ngày 2 đêm','Lịch trình','https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1100&q=80','WebDuLich Team','2026-06-05','Một hành trình ngắn ngày có thể kết hợp biển Mỹ Khê, Bà Nà Hills và phố cổ Hội An.','Ngày đầu tham quan Sơn Trà và Mỹ Khê; ngày hai Bà Nà Hills và Cầu Vàng; buổi tối đi Hội An.'),(3,'Kinh nghiệm đi Phú Quốc cho gia đình','Điểm đến','https://images.unsplash.com/photo-1548013146-72479768bada?auto=format&fit=crop&w=1100&q=80','WebDuLich Team','2026-07-08','Phú Quốc phù hợp nghỉ dưỡng, vui chơi VinWonders, Safari và trải nghiệm cáp treo Hòn Thơm.','Gia đình có trẻ em nên chọn khách sạn gần khu vui chơi, chuẩn bị kem chống nắng và chia lịch trình vừa phải.'),(4,'Miền Tây mùa nước nổi nên đi đâu?','Điểm đến','https://images.unsplash.com/photo-1469474968028-56623f02e42e?auto=format&fit=crop&w=1100&q=80','WebDuLich Team','2026-08-11','Châu Đốc, Trà Sư, Cần Thơ và Cà Mau là những điểm đến nổi bật cho hành trình miền Tây.','Các điểm nên có gồm chợ nổi Cái Răng, rừng tràm Trà Sư, nhà Công tử Bạc Liêu và Đất Mũi Cà Mau.'),(5,'Tự tạo lịch trình du lịch cần chuẩn bị gì?','Lịch trình','https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1100&q=80','WebDuLich Team','2026-09-14','Một lịch trình tốt cần có điểm đến, thời gian, ngân sách, phương tiện và nhịp độ di chuyển hợp lý.','Bạn nên xác định số ngày, điểm đến chính, điểm phụ, chi phí dự kiến và hoạt động ưu tiên.'),(6,'Top điểm đến Việt Nam nên có trong kế hoạch du lịch','Cẩm nang','https://images.unsplash.com/photo-1528127269322-539801943592?auto=format&fit=crop&w=1100&q=80','WebDuLich Team','2026-10-17','Hà Nội, Hạ Long, Ninh Bình, Đà Nẵng, Hội An, Huế, Đà Lạt, Phú Quốc và miền Tây là các lựa chọn nổi bật.','Các điểm đến này đại diện cho văn hóa, biển đảo, nghỉ dưỡng, di sản, núi rừng và sông nước.');
