INSERT INTO `destinations` VALUES (1,'Đà Nẵng','Miền Trung','Biển Mỹ Khê, Bà Nà Hills, Sơn Trà, Ngũ Hành Sơn và cầu Rồng.','biển,gia đình,checkin','https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=900&q=80','ACTIVE'),(2,'Hội An','Miền Trung','Phố cổ, đèn lồng, sông Hoài, làng gốm và ẩm thực Quảng Nam.','di sản,văn hóa,ẩm thực','https://images.unsplash.com/photo-1528127269322-539801943592?auto=format&fit=crop&w=900&q=80','ACTIVE'),(3,'Huế','Miền Trung','Đại Nội, chùa Thiên Mụ, lăng tẩm, sông Hương và ẩm thực cố đô.','di sản,văn hóa,tâm linh','https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=900&q=80','ACTIVE'),(4,'Quảng Bình','Miền Trung','Phong Nha, Thiên Đường, Nhật Lệ và hệ thống hang động nổi bật.','hang động,thiên nhiên,khám phá','https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=900&q=80','ACTIVE'),(5,'Hà Nội','Miền Bắc','Phố cổ, hồ Hoàn Kiếm, Văn Miếu, ẩm thực và văn hóa thủ đô.','văn hóa,ẩm thực,lịch sử','https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=900&q=80','ACTIVE'),(6,'Hạ Long','Miền Bắc','Vịnh Hạ Long, du thuyền, hang động và cảnh quan kỳ quan thiên nhiên.','du thuyền,biển,gia đình','https://images.unsplash.com/photo-1528127269322-539801943592?auto=format&fit=crop&w=900&q=80','ACTIVE'),(7,'Ninh Bình','Miền Bắc','Tràng An, Bái Đính, Hang Múa, Tam Cốc và cảnh quan non nước.','thiên nhiên,tâm linh,checkin','https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=900&q=80','ACTIVE'),(8,'Sapa','Miền Bắc','Fansipan, bản Cát Cát, ruộng bậc thang và khí hậu vùng cao.','núi,rừng,khám phá','https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=900&q=80','ACTIVE'),(9,'Hà Giang','Miền Bắc','Đồng Văn, Mã Pì Lèng, Quản Bạ và cung đường đá hùng vĩ.','phượt,núi,khám phá','https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=900&q=80','ACTIVE'),(10,'Mộc Châu','Miền Bắc','Đồi chè, thác Dải Yếm, bản làng và khí hậu mát mẻ.','nghỉ dưỡng,checkin,núi','https://images.unsplash.com/photo-1528127269322-539801943592?auto=format&fit=crop&w=900&q=80','ACTIVE'),(11,'Phú Quốc','Biển đảo','Grand World, VinWonders, Safari, Hòn Thơm và biển đảo nghỉ dưỡng.','biển,nghỉ dưỡng,gia đình','https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=900&q=80','ACTIVE'),(12,'Nha Trang','Biển đảo','Du ngoạn đảo, VinWonders, tắm biển và hải sản.','biển,vui chơi,ẩm thực','https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=900&q=80','ACTIVE'),(13,'Quy Nhơn','Miền Trung','Kỳ Co, Eo Gió, biển xanh và cảnh quan hoang sơ.','biển,checkin,nghỉ dưỡng','https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=900&q=80','ACTIVE'),(14,'Phú Yên','Miền Trung','Gành Đá Đĩa, Mũi Điện, Bãi Xép và thiên nhiên yên bình.','biển,checkin,thiên nhiên','https://images.unsplash.com/photo-1528127269322-539801943592?auto=format&fit=crop&w=900&q=80','ACTIVE'),(15,'Đà Lạt','Tây Nguyên','Rừng thông, khí hậu mát mẻ, quán cà phê và điểm check-in.','nghỉ dưỡng,cặp đôi,checkin','https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=900&q=80','ACTIVE'),(16,'Buôn Ma Thuột','Tây Nguyên','Thác Dray Nur, Buôn Đôn, bảo tàng cà phê và văn hóa Tây Nguyên.','văn hóa,cà phê,thiên nhiên','https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=900&q=80','ACTIVE'),(17,'Cần Thơ','Miền Nam','Chợ nổi Cái Răng, bến Ninh Kiều và sông nước miền Tây.','sông nước,ẩm thực,văn hóa','https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=900&q=80','ACTIVE'),(18,'Châu Đốc','Miền Nam','Miếu Bà Chúa Xứ, rừng tràm Trà Sư và mùa nước nổi.','tâm linh,sông nước,thiên nhiên','https://images.unsplash.com/photo-1528127269322-539801943592?auto=format&fit=crop&w=900&q=80','ACTIVE'),(19,'Cà Mau','Miền Nam','Đất Mũi, rừng ngập mặn và hành trình cực Nam Tổ quốc.','sông nước,thiên nhiên,khám phá','https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=900&q=80','ACTIVE'),(20,'Vũng Tàu','Biển đảo','Bãi Sau, tượng Chúa Kitô và tour cuối tuần gần TP.HCM.','biển,cuối tuần,gia đình','https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=900&q=80','ACTIVE'),(21,'Phan Thiết','Biển đảo','Mũi Né, Bàu Trắng, đồi cát và resort biển.','biển,nghỉ dưỡng,checkin','https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=900&q=80','ACTIVE'),(22,'Côn Đảo','Biển đảo','Bãi Đầm Trầu, Hàng Dương, di tích lịch sử và biển trong xanh.','biển,tâm linh,lịch sử','https://images.unsplash.com/photo-1528127269322-539801943592?auto=format&fit=crop&w=900&q=80','ACTIVE'),(23,'Tây Ninh','Miền Nam','Núi Bà Đen, Tòa Thánh Cao Đài và tour trong ngày.','tâm linh,leo núi,cuối tuần','https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=900&q=80','ACTIVE'),(24,'Cần Giờ','Miền Nam','Rừng Sác, đảo khỉ, biển 30/4 và sinh thái gần TP.HCM.','sinh thái,cuối tuần,gia đình','https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=900&q=80','ACTIVE');
