INSERT INTO `properties` VALUES (1,'Đà Nẵng 3N2Đ | Bà Nà - Hội An - Sơn Trà',6399000.00,'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?auto=format&fit=crop&w=1100&q=80','https://images.unsplash.com/photo-1528127269322-539801943592?auto=format&fit=crop&w=1100&q=80','https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=1100&q=80','https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1100&q=80','Đà Nẵng - Bà Nà Hills - Bán đảo Sơn Trà - Ngũ Hành Sơn - Hội An','Đang mở bán','Tour miền Trung','Đà Nẵng',3,2,24,100,2026,'Cầu Vàng Bà Nà, biển Mỹ Khê, phố cổ Hội An về đêm. Tuyến: Đà Nẵng - Bà Nà Hills - Bán đảo Sơn Trà - Ngũ Hành Sơn - Hội An. Khởi hành: Từ TP.HCM. Phương tiện: Máy bay khứ hồi & xe du lịch. Dữ liệu tour mẫu phục vụ giao diện bán tour trong nước Việt Nam.',_binary '',1,NULL,NULL,NULL,0,NULL,NULL,NULL,NULL),(2,'Đà Nẵng 4N3Đ | Bà Nà - Hội An - Huế - Phong Nha',7799000.00,'https://images.unsplash.com/photo-1528127269322-539801943592?auto=format&fit=crop&w=1100&q=80','https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=1100&q=80','https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1100&q=80','https://images.unsplash.com/photo-1548013146-72479768bada?auto=format&fit=crop&w=1100&q=80','Đà Nẵng - Hội An - Huế - Động Phong Nha','Đang mở bán','Tour miền Trung','Đà Nẵng',4,3,20,107,2026,'Khám phá miền Trung với di sản, biển xanh và hang động nổi bật. Tuyến: Đà Nẵng - Hội An - Huế - Động Phong Nha. Khởi hành: Từ TP.HCM. Phương tiện: Máy bay khứ hồi & xe du lịch. Dữ liệu tour mẫu phục vụ giao diện bán tour trong nước Việt Nam.',_binary '\0',2,NULL,NULL,NULL,0,NULL,NULL,NULL,NULL),(3,'Đà Nẵng 5N4Đ | Bà Nà - Hội An - Huế - La Vang',8999000.00,'https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?auto=format&fit=crop&w=1100&q=80','https://images.unsplash.com/photo-1500534314209-a25ddb2bd429?auto=format&fit=crop&w=1100&q=80','